import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit');
  const [step, setStep] = useState(1);


  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 3,
    features: [] as string[],
    comments: ''
  });

  const [errors, setErrors] = useState({ name: '', email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canGoNext = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    return true;
  }, [step, formData]);

  const handleNext = () => {
    if (step === 1) {
      const newErrors = {
        name: formData.name.trim() === '' ? 'Name is required' : '',
        email: !validateEmail(formData.email) ? 'Invalid email format' : ''
      };
      setErrors(newErrors);
      if (newErrors.name || newErrors.email) return;
    }
    setStep((s) => s + 1);
  };

  const handleFeatureToggle = (feature: string) => {
    setFormData((prev) => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter((f) => f !== feature)
        : [...prev.features, feature]
    }));
  };

  const onSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments
    });
  };
  const satisfactionOptions = useMemo(() => {
    return [1, 2, 3, 4, 5].map((i) => ({
      value: String(i),
      label: props.satisfactionLabels?.[i - 1] ?? `Rating ${i}`,
    }));
  }, [props.satisfactionLabels]);


  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Step {step} of 4</Heading>
          <Progress 
            value={(step / 4) * 100} 
            aria-label={`Survey progress: step ${step} of 4`} 
          />

        </Stack>

        <Card padding="var(--ggui-spacing-6)">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Personal Information</Heading>
              <Input label="Name" value={formData.name} onChange={(v: string) => setFormData(p => ({...p, name: v}))} error={errors.name} />
              <Input label="Email" value={formData.email} onChange={(v: string) => setFormData(p => ({...p, email: v}))} error={errors.email} />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction</Heading>
              <RadioGroup
                label="How satisfied are you?"
                value={String(formData.satisfaction)}
                onChange={(v: string) => setFormData(p => ({...p, satisfaction: Number(v)}))}
                options={satisfactionOptions}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Features</Heading>
              {(props.featureOptions || []).map((f) => (
                <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={() => handleFeatureToggle(f)} />
              ))}

            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Comments & Review</Heading>
              <TextArea 
                label="Open-ended comments" 
                value={formData.comments} 
                onChange={(v: string) => setFormData(p => ({...p, comments: v}))} 
                maxLength={500} 
                showCount 
              />
              <Divider />
              <Stack as="ul" gap="var(--ggui-spacing-2)" style={{ listStyle: 'none', padding: 0 }}>
                <li><Text><strong>Review Summary:</strong></Text></li>
                <li><Text>Name: {formData.name}</Text></li>
                <li><Text>Email: {formData.email}</Text></li>
                <li><Text>Satisfaction: {props.satisfactionLabels?.[formData.satisfaction - 1] ?? formData.satisfaction}</Text></li>
                <li><Text>Features: {formData.features.join(', ') || 'None'}</Text></li>
              </Stack>

            </Stack>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-2)" justify="between">
          <Button as={Clickable} variant="secondary" onClick={() => setStep(s => Math.max(1, s - 1))} disabled={step === 1}>Back</Button>
          {step < 4 ? (
            <Button as={Clickable} variant="primary" onClick={handleNext} disabled={!canGoNext}>Next</Button>
          ) : (
            <Button as={Clickable} variant="primary" onClick={onSubmit}>Submit</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );




}

