const MessageBubble = ({ message, isOwn, showHeader }: { message: StreamMessage; isOwn: boolean; showHeader: boolean }) => (
  <Stack align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
    {showHeader && (
