export default function Component(props: Props) {
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  const [inputValue, setInputValue] = useState('');
  const [localMessages, setLocalMessages] = useState<StreamMessage[]>(props.messages);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (message.latest) {
      setLocalMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: 'smooth' });
  }, [localMessages, typing.latest]);
  const [activeTypers, setActiveTypers] = useState<Set<string>>(new Set());

  useEffect(() => {
    if (typing.latest?.sender) {
      setActiveTypers((prev) => {
        const next = new Set(prev);
        if (typing.latest?.active) next.add(typing.latest.sender!);
        else next.delete(typing.latest.sender!);
        return next;
      });
    }
  }, [typing.latest]);

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const msg = { text: inputValue, timestamp: new Date().toISOString() };
    sendMessage(msg);
    setLocalMessages((prev) => [...prev, { ...msg, sender: props.currentUser }]);
    setInputValue('');
  };

  const groupedMessages = useMemo(() => {
    const groups: { sender: string; messages: StreamMessage[] }[] = [];
    localMessages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        groups.push({ sender: msg.sender || 'Unknown', messages: [msg] });
      }
    });
    return groups;
  }, [localMessages]);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4)">
      <Stack gap="var(--ggui-spacing-4)" style={{ height: '80vh' }}>
        <Row justify="between" align="center">
          <Heading level={3}>{props.title}</Heading>
          <Badge>{props.participantCount} participants</Badge>
        </Row>
          <Box
            ref={scrollRef}
            role="log"
            aria-live="polite"
            style={{ flex: 1, overflowY: 'auto' }}
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-lg)"
            style={{ border: '1px solid var(--ggui-color-outlineVariant)' }}
          >
            <Stack gap="var(--ggui-spacing-4)">
              {groupedMessages.map((group, i) => (
                <Stack key={i} gap="var(--ggui-spacing-2)" align={group.messages[0].sender === props.currentUser ? 'end' : 'start'}>
                  {group.messages.map((m, j) => (
                    <MessageBubble
                      key={j}
                      message={m}
                      isOwn={m.sender === props.currentUser}
                      showHeader={j === 0}
                    />
                  ))}
                </Stack>
              ))}
              {activeTypers.size > 0 && (
                <Text variant="caption" color="var(--ggui-color-primary-600)">
                  {Array.from(activeTypers).join(', ')} {activeTypers.size === 1 ? 'is' : 'are'} typing...
                </Text>
              )}
            </Stack>
          </Box>

        <Row gap="var(--ggui-spacing-2)">
          <Box style={{ flex: 1 }}>
                <Input
                  label="Compose message"
                  value={inputValue}
                  onChange={(val: string) => setInputValue(val)}
                  placeholder="Type a message..."
                  onKeyDown={(e: React.KeyboardEvent) => e.key === 'Enter' && handleSend()}
                />


          </Box>
          <Button
            variant="primary"
            disabled={!inputValue.trim()}
            onClick={handleSend}
          >
            Send
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

