                      role="button"
                      tabIndex={0}
                      onClick={() => setFormData((d) => ({ ...d, avatar: emoji }))}
                      onKeyDown={(e: React.KeyboardEvent) => (e.key === 'Enter' || e.key === ' ') && setFormData((d) => ({ ...d, avatar: emoji }))}
                      padding="var(--ggui-spacing-2)" 
                      borderRadius="var(--ggui-shape-radius-md)" 
                      background={formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                      style={{ cursor: 'pointer', border: formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent', transition: 'all 0.2s' }}
                    >
                      <Text size="2xl">{emoji}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Preferences</Heading>
              <Select label="Role" value={formData.role} onChange={(v) => setFormData((d) => ({ ...d, role: v }))} options={props.roleOptions.map((r) => ({ value: r, label: r }))} />
              <Toggle label="Enable Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData((d) => ({ ...d, emailNotifications: v }))} />
              <RadioGroup label="Theme" value={formData.theme} onChange={(v) => setFormData((d) => ({ ...d, theme: v }))} options={[{ label: 'Light', value: 'light' }, { label: 'Dark', value: 'dark' }]} />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review & Confirm</Heading>
              <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-surfaceVariant)">
                <Stack gap="var(--ggui-spacing-2)">
                  <Text><strong>Avatar:</strong> {formData.avatar}</Text>
                  <Text><strong>Name:</strong> {formData.name}</Text>
                  <Text><strong>Email:</strong> {formData.email}</Text>
                  <Text><strong>Role:</strong> {formData.role}</Text>
                  <Text><strong>Notifications:</strong> {formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                  <Text><strong>Theme:</strong> {formData.theme}</Text>
                </Stack>
              </Card>
            </Stack>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button onClick={handleNext} disabled={step === 1 && !isStep1Valid}>Next</Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
